1	export type Item = { kind: "sword" | "amulet" | "staff" | "potion" };
2	
3	export type QuoteStep = { kind: "quote"; items: Item[] };
4	
5	export type Scenario = {
6	  customer: { yearsWithMHPCO: number };
7	  steps: QuoteStep[];
8	};
9	
10	export type ScenarioResult = {
11	  results: unknown[];
12	};
13	
14	const BASE_PREMIUM_BY_ITEM: Record<Item["kind"], number> = {
15	  sword: 100,
16	  amulet: 60,
17	  staff: 80,
18	  potion: 40,
19	};
20	
21	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
22	const PROCESSING_FEE = 5;
23	
24	function quoteStep(step: QuoteStep) {
25	  const basePremium = BASE_PREMIUM_BY_ITEM[step.items[0].kind];
26	  const surcharge = basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
27	  const premium = basePremium + surcharge + PROCESSING_FEE;
28	  return { kind: "quote" as const, premium };
29	}
30	
31	export function processScenario(scenario: Scenario): ScenarioResult {
32	  const results = scenario.steps.map(quoteStep);
33	  return { results };
34	}
